use tonic::{transport::Server, Request, Response, Status};

// Mocking generated code from .proto
pub mod hello_world {
    pub trait Greeter {
        // In real code this is generated
        async fn say_hello(&self, request: super::Request<HelloRequest>) 
            -> Result<super::Response<HelloReply>, super::Status>;
    }
    pub struct HelloRequest { pub name: String }
    pub struct HelloReply { pub message: String }
}
use hello_world::{Greeter, HelloRequest, HelloReply};

struct MyGreeter;

// Implement the trait
impl Greeter for MyGreeter {
    async fn say_hello(&self, request: Request<HelloRequest>) 
        -> Result<Response<HelloReply>, Status> {
        let name = request.into_inner().name;
        let reply = HelloReply {
            message: format!("Hello {}!", name),
        };
        Ok(Response::new(reply))
    }
}

#[tokio::main]
async fn main() {
    println!("gRPC Server listening on [::1]:50051");
}
